// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = 3000;
const db = new Database("data.db");

db.pragma("journal_mode = WAL");
db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as {
  name: string;
}[];

if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.exec(
    "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL",
  );
}

app.use(express.json());

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

const listBookmarksStatement = db.prepare("SELECT * FROM bookmarks ORDER BY id ASC");

const getBookmarkStatement = db.prepare("SELECT * FROM bookmarks WHERE id = ?");

const createBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
  VALUES (@url, @title, @description, @folder_id, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      folder_id = @folder_id,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");

const listFoldersStatement = db.prepare("SELECT * FROM folders ORDER BY id ASC");

const getFolderStatement = db.prepare("SELECT * FROM folders WHERE id = ?");

const getFolderBookmarksStatement = db.prepare(
  "SELECT * FROM bookmarks WHERE folder_id = ? ORDER BY id ASC",
);

const createFolder = db.prepare(`
  INSERT INTO folders (name, created_at, updated_at)
  VALUES (@name, @created_at, @updated_at)
`);

const updateFolder = db.prepare(`
  UPDATE folders
  SET name = @name,
      updated_at = @updated_at
  WHERE id = @id
`);

const clearFolderBookmarks = db.prepare(
  "UPDATE bookmarks SET folder_id = NULL, updated_at = @updated_at WHERE folder_id = @folder_id",
);

const deleteFolderStatement = db.prepare("DELETE FROM folders WHERE id = ?");

const deleteFolder = db.transaction((id: number) => {
  clearFolderBookmarks.run({
    folder_id: id,
    updated_at: new Date().toISOString(),
  });
  deleteFolderStatement.run(id);
});

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseOptionalFolderId = (
  value: unknown,
): { ok: true; folderId: number | null | undefined } | { ok: false } => {
  if (value === undefined) {
    return { ok: true, folderId: undefined };
  }

  if (value === null) {
    return { ok: true, folderId: null };
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return { ok: true, folderId: value };
  }

  return { ok: false };
};

const listBookmarks = (): Bookmark[] =>
  listBookmarksStatement.all() as Bookmark[];

const getBookmark = (id: number): Bookmark | undefined =>
  getBookmarkStatement.get(id) as Bookmark | undefined;

const listFolders = (): Folder[] => listFoldersStatement.all() as Folder[];

const getFolder = (id: number): Folder | undefined =>
  getFolderStatement.get(id) as Folder | undefined;

const getFolderWithBookmarks = (id: number): FolderWithBookmarks | undefined => {
  const folder = getFolder(id);

  if (!folder) {
    return undefined;
  }

  return {
    ...folder,
    bookmarks: getFolderBookmarksStatement.all(id) as Bookmark[],
  };
};

const folderExists = (id: number): boolean => getFolder(id) !== undefined;

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/bookmarks", (req, res) => {
  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (!isNonEmptyString(url)) {
    res.status(400).json({ error: "url is required" });
    return;
  }

  if (!isNonEmptyString(title)) {
    res.status(400).json({ error: "title is required" });
    return;
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (!parsedFolderId.ok) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  if (
    parsedFolderId.folderId !== undefined &&
    parsedFolderId.folderId !== null &&
    !folderExists(parsedFolderId.folderId)
  ) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  const now = new Date().toISOString();
  const result = createBookmark.run({
    url: url.trim(),
    title: title.trim(),
    description: typeof description === "string" ? description : null,
    folder_id: parsedFolderId.folderId ?? null,
    created_at: now,
    updated_at: now,
  });

  const bookmark = getBookmark(Number(result.lastInsertRowid));
  res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  res.status(200).json(listBookmarks());
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);
  const bookmark = id === null ? undefined : getBookmark(id);

  if (!bookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const currentBookmark = getBookmark(id);

  if (!currentBookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (url !== undefined && !isNonEmptyString(url)) {
    res.status(400).json({ error: "url must be a non-empty string" });
    return;
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    res.status(400).json({ error: "title must be a non-empty string" });
    return;
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (!parsedFolderId.ok) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  if (
    parsedFolderId.folderId !== undefined &&
    parsedFolderId.folderId !== null &&
    !folderExists(parsedFolderId.folderId)
  ) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  updateBookmark.run({
    id,
    url: isNonEmptyString(url) ? url.trim() : currentBookmark.url,
    title: isNonEmptyString(title) ? title.trim() : currentBookmark.title,
    description:
      description === undefined
        ? currentBookmark.description
        : typeof description === "string"
          ? description
          : null,
    folder_id:
      parsedFolderId.folderId === undefined
        ? currentBookmark.folder_id
        : parsedFolderId.folderId,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getBookmark(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);
  const result = id === null ? { changes: 0 } : deleteBookmark.run(id);

  if (result.changes === 0) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(204).send();
});

app.post("/folders", (req, res) => {
  const { name } = req.body as {
    name?: unknown;
  };

  if (!isNonEmptyString(name)) {
    res.status(400).json({ error: "name is required" });
    return;
  }

  const now = new Date().toISOString();
  const result = createFolder.run({
    name: name.trim(),
    created_at: now,
    updated_at: now,
  });

  res.status(201).json(getFolder(Number(result.lastInsertRowid)));
});

app.get("/folders", (_req, res) => {
  res.status(200).json(listFolders());
});

app.get("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);
  const folder = id === null ? undefined : getFolderWithBookmarks(id);

  if (!folder) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  res.status(200).json(folder);
});

app.put("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null || !folderExists(id)) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  const { name } = req.body as {
    name?: unknown;
  };

  if (!isNonEmptyString(name)) {
    res.status(400).json({ error: "name is required" });
    return;
  }

  updateFolder.run({
    id,
    name: name.trim(),
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getFolder(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null || !folderExists(id)) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  deleteFolder(id);

  res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

